const symbol     = $json.symbol;
const signal     = $json.signal;
const entry      = $json.entry;
const sl         = $json.sl;
const tp         = $json.tp;
const confidence = $json.confidence;
const risk_usd   = $json.risk_usd;
const tier       = $json.tier;
const rr         = $json.rr;

// כיוון העסקה
const orderSide = signal === 'LONG' ? 'BUY' : 'SELL';

// חישוב volume לפי סיכון
const priceDistance = Math.abs(entry - sl);
let volume = priceDistance > 0 ? (risk_usd / priceDistance) : 0.01;
volume = parseFloat(volume.toFixed(2));
if (volume < 0.01) volume = 0.01;

const isValid = rr >= 1.5;

return {
    symbol          : symbol,
    order_side      : orderSide,
    entry_price     : entry,
    sl_price        : sl,
    tp_price        : tp,
    volume_to_trade : volume,
    rr_ratio        : rr,
    confidence      : confidence,
    risk_usd        : risk_usd,
    tier            : tier,
    is_rr_valid     : isValid,
    status          : isValid ? '✅ עסקה אושרה' : '❌ עסקה נחסמה'
};

const loginData = $('Auto Login').first().json.headers;
if (loginData) {
    const rawCookie = loginData['set-cookie'] || loginData['Set-Cookie'];
    const cookieArray = Array.isArray(rawCookie) ? rawCookie : [rawCookie];

    // חילוץ רק הערך הראשון לפני הפסיק (בלי Path, Domain וכו')
    const cleanCookies = cookieArray
        .map(c => c.split(';')[0].trim())
        .filter(c => !c.startsWith('co-auth=;') && !c.startsWith('rt=;'))
        .join('; ');

    return { json: { cookie: cleanCookies } };
}
return { json: { cookie: "Header not found" } };

return [
    { json: { symbol: "BTCUSDT" } },
    { json: { symbol: "ETHUSDT" } },
    { json: { symbol: "SOLUSDT" } },
    { json: { symbol: "AVAXUSDT" } }
];

const items = $input.all();
let best = null;
for (const item of items) {
    const d = item.json;
    if (d.signal === 'SKIP') continue;
    if (d.confidence < 0.50) continue;
    if (!best || d.confidence > best.confidence) {
        best = d;
    }
}
if (!best) return [{ json: { signal: 'SKIP', reason: 'No high confidence setups' } }];
return [{
    json: {
        symbol        : best.symbol,
        signal        : best.direction,
        entry         : best.entry,
        sl            : best.sl,
        tp            : best.tp,
        confidence    : best.confidence,
        risk_usd      : best.risk_usd,
        tier          : best.tier,
        rr            : best.rr,
        recent_signals: [{ type: best.direction === 'LONG' ? 'bullish' : 'bearish' }]
    }
}];

const symbol = $json.symbol;
const allowedSymbols = ['BTCUSDT', 'ETHUSDT', 'SOLUSDT', 'AVAXUSDT', 'EURUSD'];
if (!allowedSymbols.includes(symbol)) {
    return [{
        json: {
            ...($json),
            allowed: 0,
            is_rr_valid: false,
            reason: `Symbol ${symbol} not supported`
        }
    }];
}
const now = new Date();
const day = now.getUTCDay();
if (day === 5 || day === 6 || day === 0) {
    return [{ json: { ...($json), allowed: 0, is_rr_valid: false, reason: '📅 סוף שבוע - אין מסחר' } }];
}
// בדיקת active-orders (PENDING)
const pendingItems = $('Positions Amount').all();
const openSymbols = new Set();
for (const item of pendingItems) {
    const orders = item.json.orders || [];
    for (const order of orders) {
        const s = order.symbol?.replace('.cft', '').replace('.b', '').toUpperCase();
        if (s) openSymbols.add(s);
    }
}
// בדיקת open-positions (פתוחות)
const openItems = $('Position Amount 2').all();
for (const item of openItems) {
    const positions = item.json.positions || [];
    for (const pos of positions) {
        const s = pos.symbol?.replace('.cft', '').replace('.b', '').toUpperCase();
        if (s) openSymbols.add(s);
    }
}

const symbolNormalized = symbol.replace('.cft', '').replace('.b', '').toUpperCase();
if (openSymbols.has(symbolNormalized)) {
    return [{ json: { ...($json), allowed: 0, is_rr_valid: false, reason: `💼 יש פוזיציה פתוחה על ${symbol}` } }];
}
return [{ json: { ...($json), allowed: 1 } }];

