const items = $input.all();
const allSetups = [];

// בדיקת שעה נוכחית
const nowHour = new Date().getUTCHours();
if (nowHour < 8 || nowHour >= 16) {
    return [{ json: { signal: 'SKIP', reason: 'מחוץ לשעות המסחר' } }];
}

for (const item of items) {
    const { symbol, ohlcv } = item.json;
    if (!symbol || !ohlcv) continue;

    const currentPrice = ohlcv[ohlcv.length - 1].close;

    function detectSwings(ohlcv, swingLen=3) {
        const n = ohlcv.length;
        for (let i = swingLen; i < n - swingLen; i++) {
            let isHigh = true, isLow = true;
            for (let j = i - swingLen; j <= i + swingLen; j++) {
                if (j === i) continue;
                if (ohlcv[j].high >= ohlcv[i].high) isHigh = false;
                if (ohlcv[j].low  <= ohlcv[i].low)  isLow  = false;
            }
            ohlcv[i].sh = isHigh;
            ohlcv[i].sl = isLow;
        }
        return ohlcv;
    }

    function detectStructure(ohlcv) {
        let trend = 'bullish', last_sh = null, last_sl = null, events = [];
        for (let i = 0; i < ohlcv.length; i++) {
            const c = ohlcv[i];
            if (c.sh) last_sh = c.high;
            if (c.sl) last_sl = c.low;
            if (last_sh === null || last_sl === null) continue;
            if (trend === 'bullish' && c.close < last_sl) { trend = 'bearish'; events.push({ idx: i, type: 'CHOCH', direction: 'bearish' }); }
            else if (trend === 'bearish' && c.close > last_sh) { trend = 'bullish'; events.push({ idx: i, type: 'CHOCH', direction: 'bullish' }); }
            else if (trend === 'bullish' && c.close > last_sh) { events.push({ idx: i, type: 'BOS', direction: 'bullish' }); }
            else if (trend === 'bearish' && c.close < last_sl) { events.push({ idx: i, type: 'BOS', direction: 'bearish' }); }
        }
        return { ohlcv, events, trend };
    }

    function findOB(ohlcv, evIdx, direction) {
        const start = Math.max(0, evIdx - 6);
        const slice = ohlcv.slice(start, evIdx);
        const obs = [];
        for (const c of slice) {
            if (direction === 'bullish' && c.close < c.open) obs.push({ top: c.open, bottom: c.close, high: c.high, low: c.low });
            if (direction === 'bearish' && c.close > c.open) obs.push({ top: c.close, bottom: c.open, high: c.high, low: c.low });
        }
        return obs.slice(-3);
    }

    function isStrongBreak(ohlcv, idx) {
        const c = ohlcv[idx];
        const body = Math.abs(c.close - c.open);
        const rng = c.high - c.low;
        if (rng === 0) return false;
        const start = Math.max(0, idx - 20);
        const avgRange = ohlcv.slice(start, idx).reduce((s, x) => s + (x.high - x.low), 0) / (idx - start);
        return (body / rng) >= 0.5 && (rng / avgRange) >= 1.0;
    }

    function isTradingHour(timestamp) {
        const h = new Date(timestamp).getUTCHours();
        return h >= 8 && h < 16;
    }

    function findTP(ohlcv, entry, sl, direction, evIdx) {
        const lookback = Math.max(0, evIdx - 50);
        const searchCandles = ohlcv.slice(lookback);
        const risk = Math.abs(entry - sl);

        if (direction === 'bullish') {
            let resistanceOB = null;
            for (const c of searchCandles) {
                if (c.close < c.open && c.high > entry) {
                    const obTop = c.open;
                    if (obTop > entry) {
                        if (!resistanceOB || obTop < resistanceOB) resistanceOB = obTop;
                    }
                }
            }

            const liquidityLevels = [];
            for (const c of searchCandles) {
                if (c.sh && c.high > entry) liquidityLevels.push(c.high);
            }
            liquidityLevels.sort((a, b) => a - b);

            if (resistanceOB) {
                const rr = Math.abs(resistanceOB - entry) / (risk + 0.0001);
                if (rr >= 1.5) return resistanceOB;
            }

            for (const liq of liquidityLevels) {
                const rr = Math.abs(liq - entry) / (risk + 0.0001);
                if (rr >= 3 && rr <= 5) return liq;
            }

            if (liquidityLevels.length > 0) return liquidityLevels[0];
            return entry + (risk * 3);

        } else {
            let supportOB = null;
            for (const c of searchCandles) {
                if (c.close > c.open && c.low < entry) {
                    const obBottom = c.open;
                    if (obBottom < entry) {
                        if (!supportOB || obBottom > supportOB) supportOB = obBottom;
                    }
                }
            }

            const liquidityLevels = [];
            for (const c of searchCandles) {
                if (c.sl && c.low < entry) liquidityLevels.push(c.low);
            }
            liquidityLevels.sort((a, b) => b - a);

            if (supportOB) {
                const rr = Math.abs(entry - supportOB) / (risk + 0.0001);
                if (rr >= 1.5) return supportOB;
            }

            for (const liq of liquidityLevels) {
                const rr = Math.abs(entry - liq) / (risk + 0.0001);
                if (rr >= 3 && rr <= 5) return liq;
            }

            if (liquidityLevels.length > 0) return liquidityLevels[0];
            return entry - (risk * 3);
        }
    }

    const data = detectSwings(ohlcv);
    const { events } = detectStructure(data);

    for (const ev of events) {
        if (!isStrongBreak(data, ev.idx)) continue;
        if (!isTradingHour(data[ev.idx].timestamp)) continue;
        const obs = findOB(data, ev.idx, ev.direction);
        if (!obs.length) continue;

        for (const ob of obs) {
            const entry = ev.direction === 'bullish' ? ob.top : ob.bottom;

            const diff = Math.abs(entry - currentPrice) / currentPrice * 100;
            if (diff > 3) continue;

            if (ev.direction === 'bullish' && entry >= currentPrice) continue;
            if (ev.direction === 'bearish' && entry <= currentPrice) continue;

            const sl = ev.direction === 'bullish' ? ob.low * 0.998 : ob.high * 1.002;
            const tp = findTP(data, entry, sl, ev.direction, ev.idx);
            if (!tp) continue;
            const risk = Math.abs(entry - sl);
            const reward = Math.abs(tp - entry);
            const rr = reward / (risk + 0.0001);
            if (rr < 3) continue;
            const rr_capped = Math.min(rr, 5.0);
            const tp_final = ev.direction === 'bullish' ? entry + risk * rr_capped : entry - risk * rr_capped;
            const i = ev.idx;
            const candle = data[i];
            const past = data.slice(Math.max(0, i-20), i);
            const body = Math.abs(candle.close - candle.open);
            const rng = candle.high - candle.low;
            const avgVol = past.reduce((s,x) => s + x.volume, 0) / (past.length || 1);
            const avgRng = past.reduce((s,x) => s + (x.high-x.low), 0) / (past.length || 1);
            const mom3 = i >= 3 ? (candle.close - data[i-3].close) / data[i-3].close * 100 : 0;
            const vol10 = past.slice(-10).reduce((s,x) => s + (x.high-x.low), 0) / 10;

            allSetups.push({
                symbol, direction: ev.direction === 'bullish' ? 'LONG' : 'SHORT',
                order_side: ev.direction === 'bullish' ? 'BUY' : 'SELL',
                entry: Math.round(entry * 100) / 100,
                sl: Math.round(sl * 100) / 100,
                tp: Math.round(tp_final * 100) / 100,
                rr: Math.round(rr_capped * 100) / 100,
                ev_type: ev.type,
                features: {
                    body_pct: body / (rng + 0.0001),
                    volume_ratio: candle.volume / (avgVol + 0.0001),
                    hour: new Date(candle.timestamp).getUTCHours(),
                    momentum_3: mom3,
                    volatility: vol10 / (candle.close + 0.0001) * 100,
                    rr: rr_capped,
                    ev_type: ev.type === 'BOS' ? 1 : 0,
                    ob_size_ratio: (ob.top - ob.bottom) / (avgRng + 0.0001),
                    tp_distance_pct: Math.abs(tp_final - entry) / entry * 100
                }
            });
        }
    }
}

const seen = new Set();
const uniqueSetups = allSetups.filter(s => {
    const key = `${s.symbol}-${s.entry}-${s.direction}`;
    if (seen.has(key)) return false;
    seen.add(key);
    return true;
});

if (!uniqueSetups.length) return [{ json: { signal: 'SKIP', reason: 'No setups found' } }];
return uniqueSetups.map(s => ({ json: s }));

const ort = require('onnxruntime-node');
const items = $input.all();
const results = [];

const session = await ort.InferenceSession.create(
    'C:\\Users\\Magsihim_AI\\.n8n\\storage\\smc_model.onnx'
);

for (const item of items) {
    const d = item.json;
    if (d.signal === 'SKIP') continue;

    const f = d.features;

    // יצירת tensor ישירות עם array רגיל
    const tensor = new ort.Tensor(
        'float32',
        [f.body_pct, f.volume_ratio, f.hour, f.momentum_3,
         f.volatility, f.rr, f.ev_type, f.ob_size_ratio, f.tp_distance_pct],
        [1, 9]
    );

    const output = await session.run({ 'float_input': tensor });
    const confidence = output['probabilities'].data[1];

    if (confidence >= 0.80) {
        results.push({ json: { ...d, confidence: Math.round(confidence * 1000) / 1000, risk_usd: 25, tier: 'HIGH' }});
    } else if (confidence >= 0.50) {
        results.push({ json: { ...d, confidence: Math.round(confidence * 1000) / 1000, risk_usd: 15, tier: 'MEDIUM' }});
    }
}

if (!results.length) return [{ json: { signal: 'SKIP', reason: 'No high confidence setups' } }];
results.sort((a, b) => b.json.confidence - a.json.confidence);
return results;

const items = $input.all();
const results = [];
const cryptoSymbols = ['BTCUSDT', 'ETHUSDT', 'SOLUSDT', 'AVAXUSDT'];
let cryptoIndex = 0;

for (const item of items) {
    if (item.json.ohlcv) {
        results.push({ json: { symbol: item.json.symbol, ohlcv: item.json.ohlcv } });
        continue;
    }

    const symbol = cryptoSymbols[cryptoIndex];
    cryptoIndex++;
    const rawCandles = JSON.parse(item.json.data);
    const ohlcv = rawCandles.map(c => ({
        timestamp: c[0],
        open     : parseFloat(c[1]),
        high     : parseFloat(c[2]),
        low      : parseFloat(c[3]),
        close    : parseFloat(c[4]),
        volume   : parseFloat(c[5])
    }));
    results.push({ json: { symbol, ohlcv } });
}

return results;

const items = $input.all();
const seen = new Set();
const results = [];
for (const item of items) {
    const body = item.json;

    if (body['EUR/USD'] && !seen.has('EURUSD')) {
        seen.add('EURUSD');
        const values = body['EUR/USD'].values;
        const ohlcv = values.map(c => ({
            timestamp: new Date(c.datetime).getTime(),
            open: parseFloat(c.open),
            high: parseFloat(c.high),
            low: parseFloat(c.low),
            close: parseFloat(c.close),
            volume: 1
        })).reverse();
        results.push({ json: { symbol: 'EURUSD', ohlcv } });
    }
    if (body['QQQ'] && !seen.has('US100')) {
        seen.add('US100');
        const values = body['QQQ'].values;
        const ohlcv = values.map(c => ({
            timestamp: new Date(c.datetime).getTime(),
            open: parseFloat(c.open),
            high: parseFloat(c.high),
            low: parseFloat(c.low),
            close: parseFloat(c.close),
            volume: parseFloat(c.volume || 1)
        })).reverse();
        results.push({ json: { symbol: 'US100.b', ohlcv } });
    }
}
return results;
